import json
import sys
try:
    import requests
except ImportError:
    import urllib.request
    class requests:
        @staticmethod
        def get(url, params=None, timeout=15):
            if params:
                url += '?' + '&'.join(f'{k}={v}' for k, v in params.items())
            resp = urllib.request.urlopen(url, timeout=timeout)
            class R:
                status_code = resp.getcode()
                text = resp.read().decode()
                def json(self): return json.loads(self.text)
            return R()

API_KEY = '{api_key}'
QUERY = '{query}'

def shodan_search(query, api_key):
    url = 'https://api.shodan.io/shodan/host/search'
    try:
        resp = requests.get(url, params={'key': api_key, 'query': query}, timeout=15)
        return resp.json()
    except Exception as e:
        return {'error': str(e)}

print(f'=== Shodan Search ===')
print(f'Query: {QUERY}')

results = shodan_search(QUERY, API_KEY)
if 'error' in results:
    print(f'Error: {results["error"]}')
else:
    total = results.get('total', 0)
    print(f'Results: {total}')
    for match in results.get('matches', [])[:20]:
        ip = match.get('ip_str', '')
        port = match.get('port', '')
        org = match.get('org', '')
        product = match.get('product', '')
        print(f'  {ip}:{port} {org} {product}')
